mapper.update:
UPDATE EXPORT_MASTER
SET
	EXPORTER_NAME = #{exporterName}
	, REP_NAME = #{repName}
	, BIZ_REG_NO = #{bizRegNo}
	, BUYER_ID_NO = #{buyerIdNo}
	, CUSTOMS_ID = #{customsId}
	, BUYER_NAME = #{buyerName}
	, BUYER_ADDRESS = #{buyerAddress}
	, DEST_COUNTRY = #{destCountry}
	, LOADING_PORT = #{loadingPort}
	, GOODS_LOC = #{goodsLoc}
	, EXCHANGE_RATE = #{exchangeRate}
	, CURRENCY_CODE = #{currencyCode}
	, PAY_AMOUNT = #{payAmount}
	, FREIGHT_AMT = #{freightAmt}
	, INSURANCE_AMT = #{insuranceAmt}
	, CARGO_MGMT_NO = #{cargoMgmtNo}
	, BONDED_REP_NAME = #{bondedRepName}
	, CARRIER_NAME = #{carrierName}
	, VESSEL_NAME = #{vesselName}
	, LOADING_LOC = #{loadingLoc}
	, CONT_NO = #{contNo}
	, HS_CODE = #{hsCode}
	, ITEM_NAME_DECLARED = #{itemNameDeclared}
	, ITEM_NAME_TRADE = #{itemNameTrade}
	, BRAND_NAME = #{brandName}
	, TOTAL_WEIGHT = #{totalWeight}
	, TOTAL_PACK_CNT = #{totalPackCnt}
	, QTY = #{qty}
	, QTY_UNIT = #{qtyUnit}
	, INVOICE_NO = #{invoiceNo}
	, ORIGIN_COUNTRY = #{originCountry}
	, MODEL_NAME = #{modelName}
	, UNIT_PRICE = #{unitPrice}
	, TOTAL_DECL_AMT = #{totalDeclAmt}
	, STATUS = #{status}
	, EXPORT_NUMBER = #{exportNumber}
	, DCL_TYPE = #{dclType}
	, TRANS_MODE = #{transMode}
	, EXPORT_KIND = #{exportKind}
	, PAYMENT_METHOD = #{paymentMethod}
	, INCOTERMS = #{incoterms}
	, TRANSPORT_MODE = #{transportMode}
	, CONTAINER_MODE = #{containerMode}
	, GOODS_TYPE = #{goodsType}
	, REFUND_APPLICANT = #{refundApplicant}
	, INVOICE_SIGN = #{invoiceSign}
	, ATTACH_YN = #{attachYn}
	, ORIGIN_CRITERIA = #{originCriteria}
	, ORIGIN_MARK_YN = #{originMarkYn}
	, ORIGIN_CERT_TYPE = #{originCertType}
WHERE EXPORT_ID = #{exportId}

mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.SUBMIT_DATE DESC) AS RNUM, COUNT(*) OVER() AS TOTAL_COUNT, CEIL(COUNT(*) OVER() / #{cri.amount}) AS TOTAL_PAGE, A.EXPORT_ID, A.EXPORT_NUMBER, A.STATUS, A.SUBMIT_DATE, A.ITEM_NAME_DECLARED, A.DEST_COUNTRY, A.OFFICER_ID, A.DELAY_YN, C.MEM_NAME
, B.RISK_SCORE , B.RISK_RESULT , B.RISK_COMMENT , B.DOC_SCORE , B.DOC_COMMENT , B.CHECK_DATE
FROM EXPORT_MASTER A LEFT OUTER JOIN ( SELECT DOC_NUMBER, RISK_SCORE, RISK_RESULT, RISK_COMMENT, DOC_SCORE, DOC_COMMENT, CHECK_DATE, ROW_NUMBER() OVER(PARTITION BY DOC_NUMBER ORDER BY CHECK_DATE DESC) AS IDX FROM AI_DOC_CHECK ) B ON A.EXPORT_NUMBER = B.DOC_NUMBER AND B.IDX = 1 LEFT OUTER JOIN MEMBER C ON A.OFFICER_ID = C.MEM_ID
AND A.MEM_ID = #{memId}
AND A.OFFICER_ID = #{memId}
AND 1=1
AND 1=2
AND A.SUBMIT_DATE >= TO_DATE(#{cri.startDate}, 'YYYY-MM-DD')
AND A.SUBMIT_DATE < TO_DATE(#{cri.endDate}, 'YYYY-MM-DD') + 1
AND A.ITEM_NAME_DECLARED LIKE '%' || #{cri.keyword} || '%'
AND A.DEST_COUNTRY LIKE '%' || #{cri.keyword} || '%'
AND A.EXPORT_NUMBER LIKE '%' || #{cri.keyword} || '%'
AND A.STATUS IN ('WAITING', 'REVIEWING') AND (A.OFFICER_ID IS NULL OR A.DELAY_YN = 'Y')
AND A.STATUS = #{status}
) WHERE RNUM BETWEEN #{cri.startRow} AND #{cri.endRow}
